        unordered_set<int> lookup(cbegin(nums), cend(nums));
        ListNode dummy(0, head);
        for (auto curr = &dummy; curr->next;) {
            if (!lookup.count(curr->next->val)) {
                curr = curr->next;
            } else {
                // auto to_del = curr->next;
                curr->next = curr->next->next;
                // delete to_del;
